--
-- Table structure for table `fulfillments`
--

DROP TABLE IF EXISTS `fulfillments`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fulfillments` (
  `fulfillment_id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `acceptance_id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `dispatch_task_id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `order_id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `city_code` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `worker_id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `sku_id` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL,
  `status` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL,
  `started_at` timestamp NULL DEFAULT NULL,
  `completed_at` timestamp NULL DEFAULT NULL,
  `completion_note` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`fulfillment_id`),
  UNIQUE KEY `uk_fulfillments_acceptance` (`acceptance_id`),
  UNIQUE KEY `uk_fulfillments_dispatch_task` (`dispatch_task_id`),
  KEY `idx_fulfillments_city_code` (`city_code`),
  KEY `idx_fulfillments_worker_id` (`worker_id`),
  KEY `idx_fulfillments_order_id` (`order_id`),
  KEY `idx_fulfillments_status` (`status`),
  CONSTRAINT `fk_fulfillments_acceptance` FOREIGN KEY (`acceptance_id`) REFERENCES `worker_task_acceptances` (`acceptance_id`),
  CONSTRAINT `fk_fulfillments_city_code` FOREIGN KEY (`city_code`) REFERENCES `cities` (`city_code`),
  CONSTRAINT `fk_fulfillments_worker` FOREIGN KEY (`worker_id`) REFERENCES `worker_profiles` (`worker_id`),
  CONSTRAINT `chk_fulfillments_city_not_global` CHECK ((`city_code` <> _utf8mb4'__global__'))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

