--
-- Table structure for table `price_rules`
--

DROP TABLE IF EXISTS `price_rules`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `price_rules` (
  `price_rule_id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `city_code` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `sku_id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `base_price` decimal(12,2) NOT NULL,
  `price_text` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '',
  `price_type` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'fixed',
  `min_price` decimal(10,2) DEFAULT NULL,
  `max_price` decimal(10,2) DEFAULT NULL,
  `pricing_note` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `currency` varchar(8) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'CNY',
  `version` int NOT NULL DEFAULT '1',
  `is_enabled` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`price_rule_id`,`city_code`),
  KEY `idx_price_rules_city_code` (`city_code`),
  KEY `idx_price_rules_sku` (`sku_id`,`city_code`),
  CONSTRAINT `fk_price_rules_sku` FOREIGN KEY (`sku_id`, `city_code`) REFERENCES `service_skus` (`sku_id`, `city_code`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

